import{_ as t,C as a,c as i,o as n,a5 as l,G as r}from"./chunks/framework.CgT1UzWm.js";const m=JSON.parse(`{"title":"NpgsqlRest vs SQLPage: Two SQL-First Tools, Two Different Layers","titleTemplate":"NpgsqlRest","description":"NpgsqlRest and SQLPage are both SQL-first tools that connect straight to your database — but one builds REST APIs and the other builds web UIs. An honest comparison of where each fits, and why they're often complementary.","frontmatter":{"layout":"doc","outline":[2,3],"title":"NpgsqlRest vs SQLPage: Two SQL-First Tools, Two Different Layers","titleTemplate":"NpgsqlRest","description":"NpgsqlRest and SQLPage are both SQL-first tools that connect straight to your database — but one builds REST APIs and the other builds web UIs. An honest comparison of where each fits, and why they're often complementary.","head":[["meta",{"name":"keywords","content":"npgsqlrest vs sqlpage, sqlpage alternative, sql web framework, sql rest api, sqlpage rest api, build app with sql, sql-first tools, postgresql sql ui"}],["meta",{"property":"og:title","content":"NpgsqlRest vs SQLPage: Two SQL-First Tools, Two Different Layers"}],["meta",{"property":"og:description","content":"Both are SQL-first and connect straight to the database — but SQLPage renders UIs and NpgsqlRest serves APIs. Where each fits, and why they're complementary."}],["meta",{"property":"og:type","content":"article"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"NpgsqlRest vs SQLPage: Two SQL-First Tools, Two Different Layers"}],["meta",{"name":"twitter:description","content":"SQLPage renders web UIs from SQL; NpgsqlRest serves REST APIs from SQL. Different layers of the stack — and often complementary."}],["meta",{"name":"robots","content":"noindex, nofollow"}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"blog/DRAFT-npgsqlrest-vs-sqlpage.md","filePath":"blog/DRAFT-npgsqlrest-vs-sqlpage.md","lastUpdated":1782480183000}`),p={name:"blog/DRAFT-npgsqlrest-vs-sqlpage.md"};function o(h,s,d,c,g,k){const e=a("BlogNav");return n(),i("div",null,[s[0]||(s[0]=l(`<h1 id="npgsqlrest-vs-sqlpage-two-sql-first-tools-two-different-layers" tabindex="-1">NpgsqlRest vs SQLPage: Two SQL-First Tools, Two Different Layers <a class="header-anchor" href="#npgsqlrest-vs-sqlpage-two-sql-first-tools-two-different-layers" aria-label="Permalink to &quot;NpgsqlRest vs SQLPage: Two SQL-First Tools, Two Different Layers&quot;">​</a></h1><p class="blog-meta"><span class="tag">Comparison</span> · <span class="tag">SQLPage</span> · <span class="tag">SQL-First</span> · <span class="tag">June 2026</span></p><hr><p>Most comparisons on this site put NpgsqlRest next to other tools that do the same job — turning PostgreSQL into a REST API. <a href="/blog/npgsqlrest-vs-postgrest-supabase-comparison.html">PostgREST and Supabase</a> are direct competitors in that sense: all three answer the same question.</p><p><a href="https://sql-page.com" target="_blank" rel="noreferrer">SQLPage</a> is different. It shares NpgsqlRest&#39;s core idea — <strong>write SQL, not application code</strong> — but it spends that idea on the <em>other</em> end of the stack. SQLPage renders <strong>web UIs</strong> from SQL. NpgsqlRest serves <strong>REST APIs</strong> from SQL. So this isn&#39;t a &quot;which one wins&quot; piece. It&#39;s a map of where each one fits — and they fit together more often than they compete.</p><h2 id="the-shared-idea" tabindex="-1">The shared idea <a class="header-anchor" href="#the-shared-idea" aria-label="Permalink to &quot;The shared idea&quot;">​</a></h2><p>Both tools belong to the same family: logic and data live in the database, and a single self-contained binary turns SQL into something a browser can use — no ORM, no hand-written backend, no separate runtime.</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Shared foundation</th><th style="text-align:center;">NpgsqlRest</th><th style="text-align:center;">SQLPage</th></tr></thead><tbody><tr><td>SQL-first (<code>.sql</code> files are the unit of work)</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>Single self-contained binary</td><td style="text-align:center;">✅ (.NET)</td><td style="text-align:center;">✅ (Rust)</td></tr><tr><td>Connects directly to the database</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>Built-in authentication &amp; sessions</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>File uploads</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>CSV export</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>Open source</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅ (MIT)</td></tr><tr><td>Trivial deployment (copy binary, run)</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr></tbody></table></div></div><p>If you like the SQL-first philosophy, you&#39;ll feel at home in either. The difference is what comes <em>out</em> of the binary.</p><h2 id="the-fork-in-the-road" tabindex="-1">The fork in the road <a class="header-anchor" href="#the-fork-in-the-road" aria-label="Permalink to &quot;The fork in the road&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    subgraph SP [SQLPage]</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">        direction LR</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">        S1[&quot;.sql file&quot;] --&gt; S2[&quot;UI components&quot;] --&gt; S3[&quot;HTML page&quot;]</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    end</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    subgraph NR [NpgsqlRest]</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">        direction LR</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">        N1[&quot;.sql file / function&quot;] --&gt; N2[&quot;REST endpoint&quot;] --&gt; N3[&quot;JSON + typed client&quot;]</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p><strong>SQLPage maps SQL results to UI components and streams back an HTML page.</strong> Each <code>.sql</code> file is a page. You pick a component (<code>list</code>, <code>card</code>, <code>chart</code>, <code>form</code>, <code>table</code>, <code>map</code>…) and feed it rows. There is no separate frontend — SQLPage <em>is</em> the frontend.</p><p><strong>NpgsqlRest maps SQL files and functions to REST endpoints and returns JSON.</strong> Each <code>.sql</code> file or routine is an API endpoint. There is no UI — you consume the API from your own frontend (often with a <a href="/config/codegen.html">generated TypeScript client</a>), a mobile app, or another service.</p><p>That single difference — <strong>HTML out vs JSON out</strong> — is what everything else follows from.</p><h2 id="where-sqlpage-is-stronger-the-ui" tabindex="-1">Where SQLPage is stronger: the UI <a class="header-anchor" href="#where-sqlpage-is-stronger-the-ui" aria-label="Permalink to &quot;Where SQLPage is stronger: the UI&quot;">​</a></h2><p>This is SQLPage&#39;s whole identity, and it&#39;s genuinely strong. Building a page is a couple of <code>SELECT</code>s:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- users.sql — a complete, working web page</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">SELECT</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &#39;list&#39;</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> AS</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> component, </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;Users&#39;</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> AS</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> title;</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">SELECT</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> name</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> AS</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> title, email </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">AS</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> description</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">, </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;/user.sql?id=&#39;</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;"> ||</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> id </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">AS</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> link</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">FROM</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> users</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">ORDER BY</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> name</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></details><p>Want a bar chart instead? Change the component name:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">SELECT</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &#39;chart&#39;</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> AS</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> component, </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;Monthly sales&#39;</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> AS</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> title, </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;bar&#39;</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> AS</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> type</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">SELECT</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> month</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> AS</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> x, total </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">AS</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> y </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">FROM</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> sales </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">ORDER BY</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> month</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></details><p>SQLPage ships <strong>50+ components</strong> — tables, cards, forms, charts, maps (with PostGIS/Spatialite), timelines, carousels, steps — plus password auth, form handling, and even multi-database support (PostgreSQL, MySQL/MariaDB, SQLite, SQL Server, and ODBC sources like DuckDB, ClickHouse, Snowflake, and BigQuery). For an internal dashboard, an admin panel, or a data-entry tool, you can have a working interface in minutes with <strong>zero frontend code</strong>.</p><p><strong>NpgsqlRest does not do this.</strong> It does not render SQL results into UI components. What it offers on the frontend side is the <em>plumbing</em> to build your own UI:</p><ul><li><strong><a href="/config/codegen.html">TypeScript/JavaScript client generation</a></strong> — typed fetch modules generated from your endpoints, so your hand-built frontend stays in sync with the database</li><li><strong><a href="/config/static-files.html">Static file serving</a></strong> — host your frontend (or any static site) directly from the same binary</li><li><strong><a href="/config/static-files.html#content-parsing">Template parsing</a></strong> — substitute <code>{claimType}</code> placeholders (name, email, role) into HTML before serving</li></ul><p>That&#39;s useful, but it&#39;s not a UI builder. <strong>If &quot;render a UI from SQL&quot; is the goal, SQLPage wins decisively.</strong></p><h2 id="where-npgsqlrest-is-stronger-the-api" tabindex="-1">Where NpgsqlRest is stronger: the API <a class="header-anchor" href="#where-npgsqlrest-is-stronger-the-api" aria-label="Permalink to &quot;Where NpgsqlRest is stronger: the API&quot;">​</a></h2><p>SQLPage <em>can</em> emit JSON — it has a <code>json</code> component, and with <code>sqlpage.request_method()</code> you can branch on GET/POST/PUT/DELETE and hand-roll an endpoint:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">-- A JSON endpoint in SQLPage — manual, one file at a time</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">SELECT</span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;"> &#39;json&#39;</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> AS</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> component, </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;array&#39;</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> AS</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> type</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">SELECT</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> id, </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">name</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">, email </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">FROM</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> users </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">ORDER BY</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> name</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></details><p>That&#39;s fine for a simple read endpoint. SQLPage routes it automatically — like NpgsqlRest, dropping a <code>.sql</code> file gives you a URL with no route registration. But the file is an <em>imperative script that happens to output JSON</em>, not a declared endpoint. There&#39;s no inferred contract — no typed parameters, no OpenAPI, no client codegen, no per-endpoint policy. Every method check, status code, and header is something you write by hand in SQL.</p><p>NpgsqlRest is built around the API. The same kind of endpoint is generated automatically, and configured declaratively in a SQL comment:</p><details class="code-collapsible" open><summary>sql</summary><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">create</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> function</span><span style="--shiki-light:#1E66F5;--shiki-light-font-style:italic;--shiki-dark:#89B4FA;--shiki-dark-font-style:italic;"> api</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">.get_user(p_id </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">int</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">)</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">returns</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> setof user_info</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">language</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> sql</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">begin</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> atomic</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">select</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> id, </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">name</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">, email, </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">role</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> from</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> users </span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">where</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> id </span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">=</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> p_id;</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">end</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">comment on function api.get_user(int) is </span><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">HTTP GET /users/{p_id}</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@authorize admin, user</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@cached</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@cache_expires_in 300</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">@rate_limiter_policy standard</span></span>
<span class="line"><span style="--shiki-light:#40A02B;--shiki-dark:#A6E3A1;">&#39;</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div></details><p>And it brings the rest of the API platform with it:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>API capability</th><th style="text-align:center;">NpgsqlRest</th><th style="text-align:center;">SQLPage</th></tr></thead><tbody><tr><td>File-based routing (drop a <code>.sql</code> file, get a URL)</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>Expose existing functions/procedures as endpoints (no file)</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td></tr><tr><td>Inferred HTTP contract (typed params, method, response shape)</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌ (imperative script per file)</td></tr><tr><td>Path parameters (<code>/users/{id}</code>), method routing, function overloading</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td></tr><tr><td>OpenAPI / Swagger generation</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td></tr><tr><td>TypeScript client codegen + <code>.http</code> test files</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td></tr><tr><td>Per-endpoint caching (memory/Redis/hybrid)</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td></tr><tr><td>Per-endpoint rate limiting (partitioned per user/IP)</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td></tr><tr><td>Declarative auth schemes (JWT, encrypted Bearer/Cookie, OAuth, Passkey)</td><td style="text-align:center;">✅</td><td style="text-align:center;">⚠️ basic</td></tr><tr><td>Reverse proxy &amp; <a href="/config/http-client.html">HTTP client types</a> (call external APIs from SQL)</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td></tr><tr><td>Server-Sent Events streaming</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td></tr><tr><td>Error policies (RFC 7807, per-endpoint status mapping)</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td></tr><tr><td>Security headers, health checks, OpenTelemetry</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td></tr></tbody></table></div></div><p>⚠️ SQLPage has password/session auth aimed at protecting <em>pages</em>, not the multi-scheme token model an API needs.</p><p><strong>If &quot;serve a typed, policy-rich API to a frontend, mobile app, or other service&quot; is the goal, NpgsqlRest wins decisively.</strong></p><h2 id="they-re-complementary-not-rivals" tabindex="-1">They&#39;re complementary, not rivals <a class="header-anchor" href="#they-re-complementary-not-rivals" aria-label="Permalink to &quot;They&#39;re complementary, not rivals&quot;">​</a></h2><p>Here&#39;s the part most &quot;X vs Y&quot; posts miss: because they target different layers, <strong>you can run both against the same PostgreSQL database</strong> — and it&#39;s a good architecture.</p><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    DB[(&quot;PostgreSQL&quot;)]</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    SP[&quot;SQLPage&lt;br/&gt;internal dashboards,&lt;br/&gt;admin tools, reports&quot;]</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    NR[&quot;NpgsqlRest&lt;br/&gt;customer-facing REST API&lt;br/&gt;+ typed TS client&quot;]</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    DB &lt;--&gt; SP</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    DB &lt;--&gt; NR</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    SP --&gt; Ops[Internal users / analysts]</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    NR --&gt; App[Public app / mobile / partners]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>A common split:</p><ul><li><strong>SQLPage for the inside</strong> — the ops dashboard, the admin panel, the quick report a colleague needs by Friday. Things where the audience is internal and a generated UI is exactly enough.</li><li><strong>NpgsqlRest for the outside</strong> — the customer-facing API behind your product&#39;s frontend or mobile app, where you need a stable contract, typed clients, caching, rate limiting, and real auth.</li></ul><p>Both read the same tables and call the same functions. Your business logic stays in one place — the database — which is the whole point of the <a href="/blog/the-power-of-simplicity.html">SQL-first / business-rules-in-the-database</a> approach both tools share.</p><h2 id="when-to-choose-each" tabindex="-1">When to choose each <a class="header-anchor" href="#when-to-choose-each" aria-label="Permalink to &quot;When to choose each&quot;">​</a></h2><p><strong>Reach for SQLPage when:</strong></p><ul><li>You need an internal tool, dashboard, or admin UI <em>fast</em>, with no frontend stack</li><li>Your audience is analysts or internal users, not a public API consumer</li><li>You want UI components (charts, maps, forms) generated straight from queries</li><li>You&#39;re on MySQL, SQLite, SQL Server, or a warehouse like DuckDB/ClickHouse/Snowflake — SQLPage is multi-database; NpgsqlRest is PostgreSQL-only</li></ul><p><strong>Reach for NpgsqlRest when:</strong></p><ul><li>You&#39;re building an <strong>API</strong> — for your own frontend, a mobile app, partners, or AI agents</li><li>You want endpoints generated automatically with OpenAPI, typed TypeScript clients, and <code>.http</code> test files</li><li>You need production API concerns: caching, rate limiting, multiple auth schemes, retry, proxying external services, SSE</li><li>You want per-endpoint configuration version-controlled in SQL comments</li><li>You&#39;re on PostgreSQL and want to go deep on it</li></ul><p><strong>Reach for both when</strong> you have an internal side <em>and</em> an external side — which most real products do.</p><h2 id="conclusion" tabindex="-1">Conclusion <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusion&quot;">​</a></h2><p>SQLPage and NpgsqlRest answer different questions with the same philosophy. SQLPage asks <em>&quot;how do I get a UI out of SQL?&quot;</em> and answers it beautifully. NpgsqlRest asks <em>&quot;how do I get a production API out of SQL?&quot;</em> and answers that. Neither is a worse version of the other — they sit one layer apart.</p><p>If you&#39;ve already adopted the SQL-first mindset, the honest takeaway isn&#39;t &quot;switch.&quot; It&#39;s: use SQLPage where you need a screen, use NpgsqlRest where you need an endpoint, and let both lean on the same PostgreSQL so your logic never gets duplicated.</p><hr>`,49)),r(e,{"get-started":[{text:"Installation Guide",href:"/guide/installation"},{text:"Quick Start",href:"/guide/quick-start"},{text:"SQL File Source",href:"/config/sql-file-source"},{text:"TypeScript Code Generation",href:"/config/codegen"}]})])}const y=t(p,[["render",o]]);export{m as __pageData,y as default};
